/**
 * Login Functionality Test with Mocked Database
 * Tests login system with mocked database operations
 */

import { describe, it, expect, beforeEach, jest } from '@jest/globals';
import express, { Request, Response } from 'express';
import request from 'supertest';
import session from 'express-session';

// Mock storage module
const mockStorage = {
  getUserByEmail: jest.fn<() => Promise<any | null>>(),
  updateUser: jest.fn<() => Promise<any>>(),
  getUser: jest.fn<() => Promise<any | null>>(),
};

jest.mock('../../server/storage', () => ({
  storage: mockStorage,
}));

// Mock bcrypt
const mockBcrypt = {
  compare: jest.fn<() => Promise<boolean>>(),
  hash: jest.fn<() => Promise<string>>(),
};

jest.mock('bcryptjs', () => mockBcrypt);

describe('Login Functionality with Mocked Database', () => {
  let app: express.Application;
  let agent: ReturnType<typeof request.agent>;

  const testUser = {
    id: '00000000-0000-0000-0000-000000000001',
    email: 'kevin.hervieux@koveo-gestion.com',
    username: 'kevin.hervieux',
    password: '$2a$12$hashedpassword123',
    firstName: 'Kevin',
    lastName: 'Hervieux',
    role: 'admin' as const,
    language: 'fr' as const,
    isActive: true,
    lastLoginAt: null,
    createdAt: new Date(),
    updatedAt: new Date(),
  };

  beforeEach(() => {
    // Reset all mocks
    jest.clearAllMocks();

    // Create fresh Express app for each test
    app = express();
    app.use(express.json());
    app.use(express.urlencoded({ extended: true }));

    // Setup session middleware
    app.use(
      session({
        secret: 'test-secret',
        resave: false,
        saveUninitialized: false,
        cookie: { secure: false },
        name: 'koveo.sid',
      })
    );

    // Setup auth routes directly in test
    // Login route
    app.post('/api/auth/login', async (req: Request, res: Response) => {
      try {
        const { email, password } = req.body;

        if (!email || !password) {
          return res.status(400).json({
            message: 'Email and password are required',
            code: 'MISSING_CREDENTIALS',
          });
        }

        const user = await mockStorage.getUserByEmail(email.toLowerCase());

        if (!user) {
          return res.status(401).json({
            message: 'Invalid credentials',
            code: 'INVALID_CREDENTIALS',
          });
        }

        if (!user.isActive) {
          return res.status(401).json({
            message: 'Account is inactive',
            code: 'ACCOUNT_INACTIVE',
          });
        }

        const isValidPassword = await mockBcrypt.compare(password, user.password);

        if (!isValidPassword) {
          return res.status(401).json({
            message: 'Invalid credentials',
            code: 'INVALID_CREDENTIALS',
          });
        }

        // Update last login
        await mockStorage.updateUser(user.id, { lastLoginAt: new Date() });

        // Set session with user data
        req.session.userId = user.id;
        req.session.userRole = user.role;
        req.session.role = user.role;

        // Save session explicitly
        req.session.save((err) => {
          if (err) {
            return res.status(500).json({
              message: 'Session save failed',
              code: 'SESSION_SAVE_ERROR',
            });
          }

          // Return user data (without password)
          const { password: _, ...userData } = user;
          res.json({
            user: userData,
            message: 'Login successful',
          });
        });
      } catch (error: any) {
        res.status(500).json({
          message: 'Login failed',
          code: 'LOGIN_ERROR',
        });
      }
    });

    // Logout route
    app.post('/api/auth/logout', (req: Request, res: Response) => {
      req.session.destroy((err) => {
        if (err) {
          return res.status(500).json({
            message: 'Logout failed',
            code: 'LOGOUT_ERROR',
          });
        }

        res.clearCookie('koveo.sid');
        return res.json({ message: 'Logout successful' });
      });
    });

    // Get current user route
    app.get('/api/auth/user', async (req: Request, res: Response) => {
      try {
        if (!req.session?.userId) {
          return res.status(401).json({
            message: 'Not authenticated',
            code: 'NOT_AUTHENTICATED',
          });
        }

        const user = await mockStorage.getUser(req.session.userId);

        if (!user || !user.isActive) {
          req.session.destroy((err) => {
            if (err) {
              // Ignore error
            }
          });
          return res.status(401).json({
            message: 'User account not found or inactive',
            code: 'USER_INACTIVE',
          });
        }

        // Return user data without password
        const { password: _, ...userData } = user;
        return res.json(userData);
      } catch (error: any) {
        res.status(500).json({
          message: 'Authentication check failed',
          code: 'AUTH_CHECK_ERROR',
        });
      }
    });

    agent = request.agent(app);
  });

  describe('Real User Login Tests', () => {
    it('should successfully login with valid credentials', async () => {
      const loginData = {
        email: 'kevin.hervieux@koveo-gestion.com',
        password: 'admin123',
      };

      // Mock user lookup to return test user
      mockStorage.getUserByEmail.mockResolvedValue(testUser);

      // Mock password comparison to return true
      mockBcrypt.compare.mockResolvedValue(true);

      // Mock updateUser for last login update
      mockStorage.updateUser.mockResolvedValue({
        ...testUser,
        lastLoginAt: new Date(),
      });

      const response = await agent.post('/api/auth/login').send(loginData);

      expect(response.status).toBe(200);
      expect(response.body.message).toBe('Login successful');
      expect(response.body.user).toBeDefined();
      expect(response.body.user.email).toBe('kevin.hervieux@koveo-gestion.com');
      expect(response.body.user.role).toBe('admin');

      // Verify password was not included in response
      expect(response.body.user.password).toBeUndefined();

      // Verify session cookie is set
      expect(response.headers['set-cookie']).toBeDefined();
      const cookie = response.headers['set-cookie'][0];
      expect(cookie).toMatch(/koveo\.sid/);

      // Verify storage methods were called
      expect(mockStorage.getUserByEmail).toHaveBeenCalledWith('kevin.hervieux@koveo-gestion.com');
      expect(mockBcrypt.compare).toHaveBeenCalledWith('admin123', testUser.password);
      expect(mockStorage.updateUser).toHaveBeenCalledWith(
        testUser.id,
        expect.objectContaining({
          lastLoginAt: expect.any(Date),
        })
      );
    });

    it('should fail login with wrong password', async () => {
      const loginData = {
        email: 'kevin.hervieux@koveo-gestion.com',
        password: 'wrongpassword',
      };

      // Mock user lookup to return test user
      mockStorage.getUserByEmail.mockResolvedValue(testUser);

      // Mock password comparison to return false
      mockBcrypt.compare.mockResolvedValue(false);

      const response = await agent.post('/api/auth/login').send(loginData);

      expect(response.status).toBe(401);
      expect(response.body.message).toMatch(/invalid.*credentials/i);

      // Verify storage methods were called
      expect(mockStorage.getUserByEmail).toHaveBeenCalledWith('kevin.hervieux@koveo-gestion.com');
      expect(mockBcrypt.compare).toHaveBeenCalledWith('wrongpassword', testUser.password);
      expect(mockStorage.updateUser).not.toHaveBeenCalled();
    });

    it('should fail login with wrong email', async () => {
      const loginData = {
        email: 'wrong@email.com',
        password: 'admin123',
      };

      // Mock user lookup to return null (user not found)
      mockStorage.getUserByEmail.mockResolvedValue(null);

      const response = await agent.post('/api/auth/login').send(loginData);

      expect(response.status).toBe(401);
      expect(response.body.message).toMatch(/invalid.*credentials/i);

      // Verify storage methods were called
      expect(mockStorage.getUserByEmail).toHaveBeenCalledWith('wrong@email.com');
      expect(mockBcrypt.compare).not.toHaveBeenCalled();
      expect(mockStorage.updateUser).not.toHaveBeenCalled();
    });

    it('should check user session after login', async () => {
      // First login
      mockStorage.getUserByEmail.mockResolvedValue(testUser);
      mockBcrypt.compare.mockResolvedValue(true);
      mockStorage.updateUser.mockResolvedValue({
        ...testUser,
        lastLoginAt: new Date(),
      });

      const loginResponse = await agent.post('/api/auth/login').send({
        email: 'kevin.hervieux@koveo-gestion.com',
        password: 'admin123',
      });

      expect(loginResponse.status).toBe(200);

      const cookies = loginResponse.headers['set-cookie'];

      // Mock getUser for session check
      mockStorage.getUser.mockResolvedValue(testUser);

      // Check auth status with session
      const authResponse = await agent.get('/api/auth/user').set('Cookie', cookies);

      expect(authResponse.status).toBe(200);
      expect(authResponse.body.email).toBe('kevin.hervieux@koveo-gestion.com');
      expect(authResponse.body.role).toBe('admin');
      expect(authResponse.body.password).toBeUndefined();

      // Verify getUser was called
      expect(mockStorage.getUser).toHaveBeenCalledWith(testUser.id);
    });

    it('should logout and clear session', async () => {
      // First login
      mockStorage.getUserByEmail.mockResolvedValue(testUser);
      mockBcrypt.compare.mockResolvedValue(true);
      mockStorage.updateUser.mockResolvedValue({
        ...testUser,
        lastLoginAt: new Date(),
      });

      const loginResponse = await agent.post('/api/auth/login').send({
        email: 'kevin.hervieux@koveo-gestion.com',
        password: 'admin123',
      });

      expect(loginResponse.status).toBe(200);

      const cookies = loginResponse.headers['set-cookie'];

      // Logout
      const logoutResponse = await agent.post('/api/auth/logout').set('Cookie', cookies);

      expect(logoutResponse.status).toBe(200);
      expect(logoutResponse.body.message).toMatch(/logout.*success/i);

      // Try to access protected endpoint after logout
      const protectedResponse = await agent.get('/api/auth/user').set('Cookie', cookies);

      expect(protectedResponse.status).toBe(401);
      expect(protectedResponse.body.message).toMatch(/not authenticated/i);
    });
  });

  describe('Session Management', () => {
    it('should handle multiple concurrent login attempts', async () => {
      const loginData = {
        email: 'kevin.hervieux@koveo-gestion.com',
        password: 'admin123',
      };

      // Mock user lookup to return test user
      mockStorage.getUserByEmail.mockResolvedValue(testUser);

      // Mock password comparison to return true
      mockBcrypt.compare.mockResolvedValue(true);

      // Mock updateUser for last login update
      mockStorage.updateUser.mockResolvedValue({
        ...testUser,
        lastLoginAt: new Date(),
      });

      // Create multiple simultaneous login requests
      const loginPromises = Array(3)
        .fill(null)
        .map(() => request(app).post('/api/auth/login').send(loginData));

      const responses = await Promise.all(loginPromises);

      // All should succeed and get unique sessions
      responses.forEach((response) => {
        expect(response.status).toBe(200);
        expect(response.headers['set-cookie']).toBeDefined();
      });

      // Verify each got a different session
      const sessionIds = responses.map((r) => r.headers['set-cookie'][0]);
      const uniqueSessions = new Set(sessionIds);
      expect(uniqueSessions.size).toBe(3);

      // Verify storage methods were called 3 times
      expect(mockStorage.getUserByEmail).toHaveBeenCalledTimes(3);
      expect(mockBcrypt.compare).toHaveBeenCalledTimes(3);
      expect(mockStorage.updateUser).toHaveBeenCalledTimes(3);
    });
  });
});
